# Calculadora de IMC (Potência e Divisão)
# O Índice de Massa Corporal (IMC) é calculado dividindo o peso pela altura ao quadrado (peso / altura * altura)
print ("Bem-Vindo a nossa Calculadora IMC")
peso = float(input("Qual é o valor do seu peso?"))
altura = float(input("Qual é o valor da sua altura?"))
total = peso / (altura * altura)
print("O valor do seu IMC é? \n", total)